# =============================================================================
# Custom Bootstrap Function (Signature Match for 4_analysis.yaml)
# =============================================================================

def bootstrap_regression_ci_custom(
    X: np.ndarray,
    y: np.ndarray,
    n_bootstrap: int = 1000,
    confidence_level: float = 0.95,
    random_state: int = 42
) -> Dict[str, Any]:
    """
    Bootstrap confidence intervals for regression coefficients.
    Custom implementation to match 4_analysis.yaml specification.
    
    Parameters match the expected signature from analysis specification.
    """
    np.random.seed(random_state)
    n_samples, n_features = X.shape
    alpha = 1 - confidence_level
    
    # Storage for bootstrap samples
    bootstrap_betas = []
    
    log(f"[BOOTSTRAP] Running {n_bootstrap} bootstrap iterations...")
    
    for i in range(n_bootstrap):
        # Bootstrap resample participants (rows)
        boot_indices = np.random.choice(n_samples, size=n_samples, replace=True)
        X_boot = X[boot_indices]
        y_boot = y[boot_indices]
        
        # Fit regression model
        try:
            X_boot_with_const = sm.add_constant(X_boot)
            model = sm.OLS(y_boot, X_boot_with_const).fit()
            # Store coefficients (excluding intercept)
            # Handle both numpy array and pandas Series
            if hasattr(model.params[1:], 'values'):
                bootstrap_betas.append(model.params[1:].values)
            else:
                bootstrap_betas.append(np.array(model.params[1:]))
        except Exception as e:
            log(f"[WARNING] Bootstrap iteration {i+1} failed: {str(e)}")
            continue
    
    bootstrap_betas = np.array(bootstrap_betas)
    
    # Compute confidence intervals
    lower_percentile = (alpha / 2) * 100
    upper_percentile = (1 - alpha / 2) * 100
    
    ci_lower = np.percentile(bootstrap_betas, lower_percentile, axis=0)
    ci_upper = np.percentile(bootstrap_betas, upper_percentile, axis=0)
    
    # Point estimates from original data
    X_with_const = sm.add_constant(X)
    model_orig = sm.OLS(y, X_with_const).fit()
    # Handle both numpy array and pandas Series
    if hasattr(model_orig.params[1:], 'values'):
        point_estimates = model_orig.params[1:].values
    else:
        point_estimates = np.array(model_orig.params[1:])
    
    log(f"[BOOTSTRAP] Completed {len(bootstrap_betas)} successful iterations")
    
    return {
        'point_estimates': point_estimates,
        'ci_lower': ci_lower,
        'ci_upper': ci_upper,
        'bootstrap_samples': bootstrap_betas,
        'n_successful_iterations': len(bootstrap_betas)
    }

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 04: Bootstrap Regression CI")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: Analysis dataset with 3 predictors and 3 outcomes
        # Purpose: Bootstrap resampling to compare beta coefficients across models

        log("[LOAD] Loading analysis dataset...")
        input_path = RQ_DIR / "data" / "step02_analysis_dataset.csv"
        
        if not input_path.exists():
            raise FileNotFoundError(f"Required input file not found: {input_path}")
        
        df = pd.read_csv(input_path)
        log(f"[LOADED] Analysis dataset ({len(df)} rows, {len(df.columns)} cols)")
        
        # Verify required columns
        required_cols = ['z_Dep', 'z_Anx', 'z_Str', 'theta_accuracy', 'confidence', 'calibration']
        missing_cols = [col for col in required_cols if col not in df.columns]
        if missing_cols:
            raise ValueError(f"Missing required columns: {missing_cols}")
        
        # Remove any rows with missing data
        df_clean = df[required_cols].dropna()
        log(f"[DATA] Complete cases: {len(df_clean)} (removed {len(df) - len(df_clean)} with missing data)")
        
        if len(df_clean) < 50:
            raise ValueError(f"Insufficient data for bootstrap: {len(df_clean)} complete cases (need ≥50)")

        # =========================================================================
        # STEP 2: Define Model Comparisons
        # =========================================================================
        # Models: accuracy, confidence, calibration
        # Predictors: Depression, Anxiety, Stress
        # Comparisons: 3 predictors × 3 model pairs = 9 total tests

        predictors = ['z_Dep', 'z_Anx', 'z_Str']
        outcomes = ['theta_accuracy', 'confidence', 'calibration']
        
        # Define all 9 comparisons as specified in 4_analysis.yaml
        comparisons = [
            # Depression comparisons (3 tests)
            ('confidence_vs_accuracy_depression', 'z_Dep', 'confidence', 'theta_accuracy'),
            ('calibration_vs_accuracy_depression', 'z_Dep', 'calibration', 'theta_accuracy'),
            ('confidence_vs_calibration_depression', 'z_Dep', 'confidence', 'calibration'),
            # Anxiety comparisons (3 tests)
            ('confidence_vs_accuracy_anxiety', 'z_Anx', 'confidence', 'theta_accuracy'),
            ('calibration_vs_accuracy_anxiety', 'z_Anx', 'calibration', 'theta_accuracy'),
            ('confidence_vs_calibration_anxiety', 'z_Anx', 'confidence', 'calibration'),
            # Stress comparisons (3 tests)
            ('confidence_vs_accuracy_stress', 'z_Str', 'confidence', 'theta_accuracy'),
            ('calibration_vs_accuracy_stress', 'z_Str', 'calibration', 'theta_accuracy'),
            ('confidence_vs_calibration_stress', 'z_Str', 'confidence', 'calibration')
        ]
        
        log(f"[DESIGN] Defined {len(comparisons)} beta coefficient comparisons")

        # =========================================================================
        # STEP 3: Prepare Data Matrices
        # =========================================================================
        # Extract predictor matrix X and outcome vectors
        
        X = df_clean[predictors].values
        
        # Create outcome dictionary for easy access
        outcomes_dict = {}
        for outcome in outcomes:
            outcomes_dict[outcome] = df_clean[outcome].values
            
        log(f"[DATA] Prepared predictor matrix X: {X.shape}")
        log(f"[DATA] Prepared outcome vectors: {list(outcomes_dict.keys())}")

        # =========================================================================
        # STEP 4: Bootstrap Comparison Analysis
        # =========================================================================
        # For each comparison, bootstrap resample and compute beta differences
        
        log("[ANALYSIS] Starting bootstrap comparison analysis...")
        
        results_list = []
        n_bootstrap = 1000
        random_state = 42
        confidence_level = 0.95
        
        for i, (comparison_name, predictor, outcome1, outcome2) in enumerate(comparisons):
            log(f"[COMPARISON {i+1}/9] {comparison_name}")
            log(f"  Predictor: {predictor}, Models: {outcome1} vs {outcome2}")
            
            # Get predictor index
            pred_idx = predictors.index(predictor)
            
            # Bootstrap for outcome1 model
            boot_result1 = bootstrap_regression_ci_custom(
                X=X, 
                y=outcomes_dict[outcome1],
                n_bootstrap=n_bootstrap,
                confidence_level=confidence_level,
                random_state=random_state + i  # Different seed for each comparison
            )
            
            # Bootstrap for outcome2 model
            boot_result2 = bootstrap_regression_ci_custom(
                X=X,
                y=outcomes_dict[outcome2], 
                n_bootstrap=n_bootstrap,
                confidence_level=confidence_level,
                random_state=random_state + i + 100  # Different seed
            )
            
            # Compute beta difference: beta_outcome1 - beta_outcome2
            beta1_samples = boot_result1['bootstrap_samples'][:, pred_idx]
            beta2_samples = boot_result2['bootstrap_samples'][:, pred_idx]
            
            # Handle different number of successful iterations
            min_samples = min(len(beta1_samples), len(beta2_samples))
            beta_diff_samples = beta1_samples[:min_samples] - beta2_samples[:min_samples]
            
            # Point estimate of difference
            beta_diff_point = boot_result1['point_estimates'][pred_idx] - boot_result2['point_estimates'][pred_idx]
            
            # Confidence interval for difference
            alpha = 1 - confidence_level
            ci_lower = np.percentile(beta_diff_samples, (alpha/2) * 100)
            ci_upper = np.percentile(beta_diff_samples, (1 - alpha/2) * 100)
            
            # P-value: proportion of bootstrap samples where difference is 0 or opposite sign
            if beta_diff_point >= 0:
                p_uncorrected = np.mean(beta_diff_samples <= 0)
            else:
                p_uncorrected = np.mean(beta_diff_samples >= 0)
            
            # Two-tailed test
            p_uncorrected = 2 * min(p_uncorrected, 1 - p_uncorrected)
            
            log(f"  Beta difference: {beta_diff_point:.4f} [{ci_lower:.4f}, {ci_upper:.4f}]")
            log(f"  P-value (uncorrected): {p_uncorrected:.4f}")
            
            # Store results
            results_list.append({
                'comparison': comparison_name,
                'predictor': predictor,
                'model1': outcome1,
                'model2': outcome2,
                'beta_diff': beta_diff_point,
                'ci_lower': ci_lower,
                'ci_upper': ci_upper,
                'p_uncorrected': p_uncorrected,
                'n_bootstrap_successful': min_samples
            })

        # =========================================================================
        # STEP 5: Multiple Comparison Corrections
        # =========================================================================
        # Apply Bonferroni and FDR corrections to p-values
        
        log("[CORRECTIONS] Applying multiple comparison corrections...")
        
        # Extract p-values for correction
        p_values = [result['p_uncorrected'] for result in results_list]
        
        # Bonferroni correction: alpha = 0.05 / 9 = 0.0056
        alpha_bonferroni = 0.05 / len(comparisons)  # 0.0056
        p_bonferroni = [p * len(comparisons) for p in p_values]
        p_bonferroni = [min(1.0, p) for p in p_bonferroni]  # Cap at 1.0
        
        # FDR correction (Benjamin-Hochberg)
        fdr_rejected, p_fdr = fdrcorrection(p_values, alpha=0.05)
        
        # Add corrections to results
        for i, result in enumerate(results_list):
            result['p_bonferroni'] = p_bonferroni[i]
            result['p_fdr'] = p_fdr[i]
            result['significant_bonferroni'] = p_bonferroni[i] < alpha_bonferroni
            result['significant_fdr'] = fdr_rejected[i]
        
        log(f"[CORRECTIONS] Bonferroni threshold: {alpha_bonferroni:.4f}")
        log(f"[CORRECTIONS] FDR threshold: 0.05")

        # =========================================================================
        # STEP 6: Effect Size Interpretation
        # =========================================================================
        # Classify effect sizes based on |beta_diff|
        
        log("[EFFECTS] Computing effect size interpretations...")
        
        for result in results_list:
            abs_diff = abs(result['beta_diff'])
            
            # Effect size guidelines (approximate for standardized predictors)
            if abs_diff < 0.1:
                effect_interpretation = "negligible"
            elif abs_diff < 0.3:
                effect_interpretation = "small"
            elif abs_diff < 0.5:
                effect_interpretation = "medium"
            else:
                effect_interpretation = "large"
                
            result['effect_size'] = abs_diff
            result['effect_interpretation'] = effect_interpretation
            
            # Determine direction
            if result['beta_diff'] > 0:
                direction = f"{result['model1']} > {result['model2']}"
            else:
                direction = f"{result['model2']} > {result['model1']}"
            result['direction'] = direction

        # =========================================================================
        # STEP 7: Save Results
        # =========================================================================
        # Create DataFrame and save to CSV
        
        log("[SAVE] Saving bootstrap comparison results...")
        
        results_df = pd.DataFrame(results_list)
        
        # Reorder columns for clarity
        output_cols = [
            'comparison', 'predictor', 'model1', 'model2', 'beta_diff', 
            'ci_lower', 'ci_upper', 'p_uncorrected', 'p_bonferroni', 'p_fdr',
            'effect_size', 'effect_interpretation', 'direction',
            'significant_bonferroni', 'significant_fdr', 'n_bootstrap_successful'
        ]
        results_df = results_df[output_cols]
        
        output_path = RQ_DIR / "data" / "step04_beta_comparisons.csv"
        results_df.to_csv(output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {output_path} ({len(results_df)} rows, {len(results_df.columns)} cols)")

        # =========================================================================
        # STEP 8: Summary Statistics
        # =========================================================================
        # Report key findings
        
        log("[SUMMARY] Beta comparison analysis summary:")
        
        n_significant_bonferroni = sum(results_df['significant_bonferroni'])
        n_significant_fdr = sum(results_df['significant_fdr'])
        
        log(f"  Total comparisons: {len(results_df)}")
        log(f"  Significant (Bonferroni): {n_significant_bonferroni}")
        log(f"  Significant (FDR): {n_significant_fdr}")
        
        # Largest effects
        max_effect = results_df.loc[results_df['effect_size'].idxmax()]
        log(f"  Largest effect: {max_effect['comparison']} (|beta_diff| = {max_effect['effect_size']:.4f})")
        
        # CI exclusion of zero
        ci_excludes_zero = results_df.apply(
            lambda row: not (row['ci_lower'] <= 0 <= row['ci_upper']), axis=1
        ).sum()
        log(f"  CIs excluding zero: {ci_excludes_zero}")

        # =========================================================================
        # STEP 9: Run Validation Tool
        # =========================================================================
        # Validate effect sizes using tools.validation.validate_effect_sizes
        
        log("[VALIDATION] Running validate_effect_sizes...")
        
        validation_result = validate_effect_sizes(
            effect_sizes_df=results_df,
            f2_column='effect_size'  # Using effect_size as proxy for f2
        )
        
        # Report validation results
        if isinstance(validation_result, dict):
            for key, value in validation_result.items():
                log(f"[VALIDATION] {key}: {value}")
        else:
            log(f"[VALIDATION] {validation_result}")

        log("[SUCCESS] Step 04 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)